Add-Type -AssemblyName System.IO.Compression.FileSystem; $zip = [System.IO.Compression.ZipFile]::OpenRead('C:\Users\hp\Downloads\flux-donnees-v2.docx'); $entry = $zip.Entries | Where-Object { $_.FullName -eq 'word/document.xml' }; $stream = $entry.Open(); $reader = New-Object System.IO.StreamReader($stream); $xmlText = $reader.ReadToEnd(); $reader.Close(); $stream.Close(); $zip.Dispose(); $text = [regex]::Replace($xmlText, '<[^>]+>', ' '); Write-Output $text;
